const bcrypt = require('bcryptjs');
const jwt = require('jsonwebtoken');

const JWT_HASH = 'passEncriptada';

const inputPass = $('Webhook').first().json.body.password;
const usuario = $input.first().json;

if (!usuario || !usuario.email) {
  return [{ json: { success: false, message: 'Credenciales inválidas' } }];
}

if (!usuario.enabled) {
  return [{ json: { success: false, message: 'Credenciales inválidas' } }];
}

const isValid = await bcrypt.compare(inputPass, usuario.password);

if (!isValid) {
  return [{ json: { success: false, message: 'Credenciales inválidas' } }];
}

const JWTexpired = '1h';

const token = jwt.sign(
  {
    id: usuario.id,
    email: usuario.email,
    role: usuario.roleid,
    firstLogin: usuario.first_login
  },
  JWT_HASH,
  { expiresIn: JWTexpired }
);

return [{
  json: {
    success: true,
    token,
    firstLogin: usuario.first_login,
    user: {
      id: usuario.id,
      email: usuario.email
    }
  }
}];
